    #[test]
    fn approval_and_diff_commands_decode_protocol_params() {
        let session_id = SessionKey("local:test".into());
        let approval_id = ApprovalId::new();
        let approval = RpcRequest::new(
            "approval-1",
            methods::APPROVAL_RESPOND,
            json!({
                "session_id": session_id.clone(),
                "approval_id": approval_id.clone(),
                "decision": "approve",
            }),
        );

        assert!(matches!(
            route_rpc_command(approval, ConnectionUiFeatures::default()).expect("approval/respond routes"),
            UiCommand::ApprovalRespond(ApprovalRespondParams {
                session_id: decoded_session_id,
                approval_id: decoded_approval_id,
                decision: ApprovalDecision::Approve,
                ..
            }) if decoded_session_id == session_id && decoded_approval_id == approval_id
        ));

        let preview_id = PreviewId::new();
        let diff = RpcRequest::new(
            "diff-1",
            methods::DIFF_PREVIEW_GET,
            json!({
                "session_id": session_id.clone(),
                "preview_id": preview_id.clone(),
            }),
        );

        assert!(matches!(
            route_rpc_command(diff, ConnectionUiFeatures::default()).expect("diff/preview/get routes"),
            UiCommand::DiffPreviewGet(DiffPreviewGetParams {
                session_id: decoded_session_id,
                preview_id: decoded_preview_id,
            }) if decoded_session_id == session_id && decoded_preview_id == preview_id
        ));

        let task_id = TaskId::new();
        let task_cancel = RpcRequest::new(
            "task-cancel",
            methods::TASK_CANCEL,
            json!({
                "session_id": session_id.clone(),
                "task_id": task_id.clone(),
            }),
        );
        assert!(matches!(
            route_rpc_command(task_cancel, ConnectionUiFeatures::default()).expect("task/cancel routes"),
            UiCommand::TaskCancel(TaskCancelParams {
                session_id: Some(decoded_session_id),
                task_id: decoded_task_id,
                ..
            }) if decoded_session_id == session_id && decoded_task_id == task_id
        ));
    }

    #[test]
    fn server_supported_methods_are_route_complete() {
        let session_id = SessionKey("local:test".into());
        let turn_id = TurnId::new();
        let approval_id = ApprovalId::new();
        let preview_id = PreviewId::new();
        let task_id = octos_core::TaskId::new();

        for request in [
            RpcRequest::new(
                "session-open",
                methods::SESSION_OPEN,
                json!({ "session_id": session_id.clone() }),
            ),
            RpcRequest::new(
                "turn-start",
                methods::TURN_START,
                json!({
                    "session_id": session_id.clone(),
                    "turn_id": turn_id.clone(),
                    "input": [{ "kind": "text", "text": "hello" }],
                }),
            ),
            RpcRequest::new(
                "turn-interrupt",
                methods::TURN_INTERRUPT,
                json!({
                    "session_id": session_id.clone(),
                    "turn_id": turn_id.clone(),
                }),
            ),
            RpcRequest::new(
                "approval-respond",
                methods::APPROVAL_RESPOND,
                json!({
                    "session_id": session_id.clone(),
                    "approval_id": approval_id.clone(),
                    "decision": "approve",
                }),
            ),
            RpcRequest::new(
                "diff-preview",
                methods::DIFF_PREVIEW_GET,
                json!({
                    "session_id": session_id.clone(),
                    "preview_id": preview_id.clone(),
                }),
            ),
            RpcRequest::new(
                "task-output",
                methods::TASK_OUTPUT_READ,
                json!({
                    "session_id": session_id.clone(),
                    "task_id": task_id.clone(),
                }),
            ),
            RpcRequest::new(
                "task-list",
                methods::TASK_LIST,
                json!({
                    "session_id": session_id.clone(),
                }),
            ),
            RpcRequest::new(
                "task-cancel",
                methods::TASK_CANCEL,
                json!({
                    "session_id": session_id.clone(),
                    "task_id": task_id.clone(),
                }),
            ),
            RpcRequest::new(
                "task-restart",
                methods::TASK_RESTART_FROM_NODE,
                json!({
                    "session_id": session_id.clone(),
                    "task_id": task_id.clone(),
                    "node_id": "design",
                }),
            ),
        ] {
            let method = request.method.clone();
            assert!(
                ui_protocol_server_supported_methods().contains(&method.as_str()),
                "{method} should be advertised by the server slice"
            );
            let command = route_rpc_command(request, ConnectionUiFeatures::default())
                .expect("server-supported method routes");
            assert_eq!(command.method(), method);
        }
    }

    fn appui_task_state_with_running_task(
        session_id: &SessionKey,
    ) -> (Arc<AppState>, Arc<octos_agent::TaskSupervisor>, TaskId) {
        let supervisor = Arc::new(octos_agent::TaskSupervisor::new());
        let task_id = supervisor.register(
            "run_pipeline",
            "call-appui-task",
            Some(&session_id.to_string()),
        );
        supervisor.mark_running(&task_id);
        let parsed_task_id = task_id
            .parse::<TaskId>()
            .expect("supervisor task id is UUID");

        let store = crate::session_actor::SessionTaskQueryStore::default();
        let tmp = tempfile::tempdir().expect("tempdir");
        store.register(session_id, &supervisor, tmp.path());
        let state = Arc::new(AppState {
            task_query_store: Some(store),
            ..AppState::empty_for_tests()
        });
        (state, supervisor, parsed_task_id)
    }

    async fn recv_rpc_json(rx: &mut mpsc::Receiver<WsMessage>) -> Value {
        match rx.recv().await.expect("rpc frame") {
            WsMessage::Text(text) => serde_json::from_str(text.as_str()).expect("json frame"),
            other => panic!("expected text frame, got {other:?}"),
        }
    }

    /// #966 / M13-B projection contract: when the `TaskSupervisor`
    /// query JSON carries the M13-B extension fields (`source`, `role`,
    /// `summary`, `artifact_count`, `runtime_policy_stamp`), the
    /// `task_list_entry_from_value` projection MUST round-trip them
    /// onto the wire `TaskListEntry` so downstream `task/list` and
    /// `task/updated` payloads include them verbatim.
    ///
    /// PR #1103 added the wire fields and the supervisor-side projection
    /// fields. This guard pins the deserialization end-to-end so a
    /// future supervisor that emits these fields is read correctly with
    /// no further wire wiring needed.
    #[test]
    fn task_list_entry_from_value_round_trips_m13b_projection_fields() {
        let now = Utc::now();
        let raw = json!({
            "id": "0190d000-0000-7000-8000-000000000001",
            "tool_name": "spawn_agent",
            "tool_call_id": "call-1",
            "status": "running",
            "lifecycle_state": "running",
            "runtime_state": "executing_tool",
            "source": "model",
            "role": "reviewer",
            "summary": "scanning diff for P0 findings",
            "artifact_count": 3,
            "runtime_policy_stamp": {
                "model": "claude-opus-4-7",
                "sandbox": "macos",
                "approval_policy": "ask",
            },
            "parent_session_key": "api:parent",
            "child_session_key": "api:parent#child-1",
            "started_at": now,
            "updated_at": now,
        });
        let entry =
            task_list_entry_from_value(raw).expect("M13-B projection JSON must deserialize");
        assert_eq!(entry.source.as_deref(), Some("model"));
        assert_eq!(entry.role.as_deref(), Some("reviewer"));
        assert_eq!(
            entry.summary.as_deref(),
            Some("scanning diff for P0 findings")
        );
        assert_eq!(entry.artifact_count, Some(3));
        let stamp = entry
            .runtime_policy_stamp
            .as_ref()
            .expect("runtime_policy_stamp must round-trip");
        assert_eq!(stamp["model"], json!("claude-opus-4-7"));
        assert_eq!(stamp["sandbox"], json!("macos"));
        assert_eq!(stamp["approval_policy"], json!("ask"));
        // Legacy fields still round-trip.
        assert_eq!(entry.tool_name, "spawn_agent");
        assert_eq!(entry.status, "running");
    }

    /// #966 / M13-B back-compat: a legacy `TaskSupervisor` query JSON
    /// payload that does NOT include the M13-B extension fields must
    /// still deserialize cleanly with `None` for each new field. Guards
    /// against a future change that accidentally makes any new field
    /// required (which would break every existing supervisor).
    #[test]
    fn task_list_entry_from_value_tolerates_legacy_supervisor_json() {
        let now = Utc::now();
        let raw = json!({
            "id": "0190d000-0000-7000-8000-000000000002",
            "tool_name": "run_pipeline",
            "tool_call_id": "call-2",
            "status": "completed",
            "lifecycle_state": "ready",
            "runtime_state": "completed",
            "started_at": now,
            "updated_at": now,
        });
        let entry =
            task_list_entry_from_value(raw).expect("legacy supervisor JSON must deserialize");
        assert!(entry.source.is_none());
        assert!(entry.role.is_none());
        assert!(entry.summary.is_none());
        assert!(entry.artifact_count.is_none());
        assert!(entry.runtime_policy_stamp.is_none());
    }

