    #[test]
    fn m15_raw_goal_and_loop_stubs_use_in_memory_state() {
        clear_autonomy_runtime_state_for_test();
        let features = ConnectionUiFeatures::stdio_defaults();
        let session_id = SessionKey::new("api", "m15-stub");

        let goal_set = RpcRequest::new(
            "goal-set",
            methods::SESSION_GOAL_SET,
            json!({
                "session_id": session_id.clone(),
                "objective": "finish the review",
                "token_budget": 12_000
            }),
        );
        let result = raw_autonomy_rpc(&goal_set, features, None).expect("goal set");
        assert_eq!(result["goal"]["status"], json!("active"));
        assert_eq!(result["goal"]["token_budget"], json!(12_000));
        assert_eq!(result["transition_actor"], json!("user"));

        let goal_get = RpcRequest::new(
            "goal-get",
            methods::SESSION_GOAL_GET,
            json!({ "session_id": session_id.clone() }),
        );
        let result = raw_autonomy_rpc(&goal_get, features, None).expect("goal get");
        assert_eq!(result["goal"]["objective"], json!("finish the review"));

        let loop_create = RpcRequest::new(
            "loop-create",
            methods::LOOP_CREATE,
            json!({
                "session_id": session_id.clone(),
                "command": "/loop check deploy every 20m"
            }),
        );
        let result = raw_autonomy_rpc(&loop_create, features, None).expect("loop create");
        assert_eq!(result["session_id"], json!(session_id.clone()));
        assert_eq!(result["ok"], json!(true));
        assert_eq!(result["status"], json!("active"));
        assert_eq!(result["loop"]["mode"], json!("fixed_interval"));
        assert_eq!(result["loop"]["interval_seconds"], json!(1_200));
        assert_eq!(result["fire"]["queued"], json!(false));
        assert_eq!(result["fire"]["reason"], json!("waiting_for_schedule"));
        let loop_id = result["loop"]["loop_id"]
            .as_str()
            .expect("loop id")
            .to_owned();

        let loop_list = RpcRequest::new(
            "loop-list",
            methods::LOOP_LIST,
            json!({ "session_id": session_id.clone() }),
        );
        let result = raw_autonomy_rpc(&loop_list, features, None).expect("loop list");
        assert_eq!(result["session_id"], json!(session_id.clone()));
        assert_eq!(result["loops"][0]["loop_id"], json!(loop_id));

        let agent_list = RpcRequest::new(
            "agent-list",
            methods::AGENT_LIST,
            json!({ "session_id": session_id.clone() }),
        );
        let result = raw_autonomy_rpc(&agent_list, features, None).expect("agent list");
        assert_eq!(result["session_id"], json!(session_id.clone()));
        assert_eq!(result["agents"], json!([]));

        let fire_now = RpcRequest::new(
            "loop-fire",
            methods::LOOP_FIRE_NOW,
            json!({ "session_id": session_id, "loop_id": loop_id }),
        );
        let result = raw_autonomy_rpc(&fire_now, features, None).expect("loop fire queues");
        assert_eq!(result["ok"], json!(true));
        assert_eq!(result["status"], json!("queued"));
        assert_eq!(result["fire"]["queued"], json!(true));
        assert_eq!(result["fire"]["duplicate"], json!(false));
        assert_eq!(result["fire"]["reason"], json!("LoopFire"));
    }

    #[derive(Default)]
    struct RecordingOrchestrator {
        calls: std::sync::Mutex<Vec<String>>,
    }

    impl RecordingOrchestrator {
        fn record(&self, call: impl Into<String>) -> Result<Value, RpcError> {
            let call = call.into();
            self.calls
                .lock()
                .expect("recording lock")
                .push(call.clone());
            Ok(json!({ "called": call }))
        }
    }

    impl AgentOrchestrator for RecordingOrchestrator {
        fn list_agents(&self, request: AgentListRequest) -> Result<Value, RpcError> {
            self.record(format!("list_agents:{}", request.profile_id))
        }

        fn read_agent_status(&self, request: AgentRequest) -> Result<Value, RpcError> {
            self.record(format!("read_agent_status:{}", request.agent_id))
        }

        fn read_agent_output(&self, request: AgentOutputRequest) -> Result<Value, RpcError> {
            self.record(format!("read_agent_output:{}", request.agent_id))
        }

        fn list_agent_artifacts(&self, request: AgentRequest) -> Result<Value, RpcError> {
            self.record(format!("list_agent_artifacts:{}", request.agent_id))
        }

        fn read_agent_artifact(
            &self,
            request: AgentArtifactReadRequest,
        ) -> Result<Value, RpcError> {
            self.record(format!("read_agent_artifact:{}", request.agent_id))
        }

        fn interrupt_agent(&self, request: AgentRequest) -> Result<Value, RpcError> {
            self.record(format!("interrupt_agent:{}", request.agent_id))
        }

        fn close_agent(&self, request: AgentRequest) -> Result<Value, RpcError> {
            self.record(format!("close_agent:{}", request.agent_id))
        }

        fn get_goal(&self, request: GoalSessionRequest) -> Result<Value, RpcError> {
            self.record(format!("get_goal:{}", request.session_id))
        }

        fn set_goal(&self, request: GoalSetRequest) -> Result<Value, RpcError> {
            self.record(format!("set_goal:{}", request.session_id))
        }

        fn clear_goal(&self, request: GoalSessionRequest) -> Result<Value, RpcError> {
            self.record(format!("clear_goal:{}", request.session_id))
        }

        fn create_loop(&self, request: LoopCreateRequest) -> Result<Value, RpcError> {
            self.record(format!("create_loop:{}", request.session_id))
        }

        fn list_loops(&self, request: LoopListRequest) -> Result<Value, RpcError> {
            self.record(format!("list_loops:{}", request.profile_id))
        }

        fn control_loop(&self, request: LoopControlRequest) -> Result<Value, RpcError> {
            let kind = match request.kind {
                LoopControlKind::Delete => "delete",
                LoopControlKind::Pause => "pause",
                LoopControlKind::Resume => "resume",
                LoopControlKind::FireNow => "fire_now",
            };
            self.record(format!("control_loop:{kind}:{}", request.loop_id))
        }
    }

    #[test]
    fn m15_raw_autonomy_rpc_dispatches_every_method_to_orchestrator() {
        let features = ConnectionUiFeatures::stdio_defaults();
        let session_id = SessionKey::new("api", "m15-orchestrator");
        let orchestrator = RecordingOrchestrator::default();
        let cases = vec![
            (
                methods::AGENT_LIST,
                json!({ "session_id": session_id.clone(), "profile_id": "main" }),
                "list_agents:main",
            ),
            (
                methods::AGENT_STATUS_READ,
                json!({ "agent_id": "agent-1", "session_id": session_id.clone() }),
                "read_agent_status:agent-1",
            ),
            (
                methods::AGENT_OUTPUT_READ,
                json!({ "agent_id": "agent-1", "session_id": session_id.clone(), "limit": 10 }),
                "read_agent_output:agent-1",
            ),
            (
                methods::AGENT_ARTIFACT_LIST,
                json!({ "agent_id": "agent-1", "session_id": session_id.clone() }),
                "list_agent_artifacts:agent-1",
            ),
            (
                methods::AGENT_ARTIFACT_READ,
                json!({ "agent_id": "agent-1", "artifact_id": "artifact-1", "session_id": session_id.clone() }),
                "read_agent_artifact:agent-1",
            ),
            // #965 — task/artifact/* must route through the same
            // orchestrator handlers as agent/artifact/* so the M13
            // contract direction (task/* canonical names) works
            // alongside the legacy agent/* aliases.
            (
                methods::TASK_ARTIFACT_LIST,
                json!({ "agent_id": "agent-2", "session_id": session_id.clone() }),
                "list_agent_artifacts:agent-2",
            ),
            (
                methods::TASK_ARTIFACT_READ,
                json!({ "agent_id": "agent-2", "artifact_id": "artifact-2", "session_id": session_id.clone() }),
                "read_agent_artifact:agent-2",
            ),
            (
                methods::AGENT_INTERRUPT,
                json!({ "agent_id": "agent-1", "session_id": session_id.clone() }),
                "interrupt_agent:agent-1",
            ),
            (
                methods::AGENT_CLOSE,
                json!({ "agent_id": "agent-1", "session_id": session_id.clone() }),
                "close_agent:agent-1",
            ),
            (
                methods::SESSION_GOAL_GET,
                json!({ "session_id": session_id.clone() }),
                "get_goal:api:m15-orchestrator",
            ),
            (
                methods::SESSION_GOAL_SET,
                json!({ "session_id": session_id.clone(), "objective": "ship it" }),
                "set_goal:api:m15-orchestrator",
            ),
            (
                methods::SESSION_GOAL_CLEAR,
                json!({ "session_id": session_id.clone() }),
                "clear_goal:api:m15-orchestrator",
            ),
            (
                methods::LOOP_CREATE,
                json!({ "session_id": session_id.clone(), "command": "/loop ship every 20m" }),
                "create_loop:api:m15-orchestrator",
            ),
            (
                methods::LOOP_LIST,
                json!({ "session_id": session_id.clone() }),
                "list_loops:_main",
            ),
            (
                methods::LOOP_DELETE,
                json!({ "loop_id": "loop-1", "session_id": session_id.clone() }),
                "control_loop:delete:loop-1",
            ),
            (
                methods::LOOP_PAUSE,
                json!({ "loop_id": "loop-1", "session_id": session_id.clone() }),
                "control_loop:pause:loop-1",
            ),
            (
                methods::LOOP_RESUME,
                json!({ "loop_id": "loop-1", "session_id": session_id.clone() }),
                "control_loop:resume:loop-1",
            ),
            (
                methods::LOOP_FIRE_NOW,
                json!({ "loop_id": "loop-1", "session_id": session_id.clone() }),
                "control_loop:fire_now:loop-1",
            ),
        ];

        for (method, params, expected_call) in &cases {
            let request = RpcRequest::new(*expected_call, *method, params.clone());
            let result =
                raw_autonomy_rpc_with_orchestrator(&request, features, None, &orchestrator)
                    .expect("raw M15 RPC should dispatch to orchestrator");
            assert_eq!(result["called"], json!(expected_call));
        }

        let calls = orchestrator.calls.lock().expect("recorded calls").clone();
        let expected = cases
            .iter()
            .map(|(_, _, expected_call)| (*expected_call).to_owned())
            .collect::<Vec<_>>();
        assert_eq!(calls, expected);
    }

    /// Codex P1 follow-up to #1094: `task/artifact/list` and
    /// `task/artifact/read` are the UPCR-2026-019 / M13 canonical names.
    /// Spec-conforming clients reach them via `task/list`, which exposes
    /// `task_id`, so these aliases MUST accept `task_id` (not just the
    /// legacy `agent_id`) and resolve it to the backing agent. The legacy
    /// `agent_id` shape stays working too.
    #[test]
    fn task_artifact_alias_accepts_task_id_and_agent_id() {
        let features = ConnectionUiFeatures::stdio_defaults();
        let session_id = SessionKey::new("api", "task-artifact-alias");
        let orchestrator = RecordingOrchestrator::default();

        // task/artifact/list with `task_id` only (spec-conforming shape).
        let list_with_task_id = RpcRequest::new(
            "req-list-task",
            methods::TASK_ARTIFACT_LIST,
            json!({ "task_id": "task-spec", "session_id": session_id.clone() }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&list_with_task_id, features, None, &orchestrator)
                .expect("task/artifact/list with task_id should succeed");
        assert_eq!(result["called"], json!("list_agent_artifacts:task-spec"));

        // task/artifact/read with `task_id` + `artifact_id` only.
        let read_with_task_id = RpcRequest::new(
            "req-read-task",
            methods::TASK_ARTIFACT_READ,
            json!({
                "task_id": "task-spec-2",
                "artifact_id": "artifact-1",
                "session_id": session_id.clone(),
            }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&read_with_task_id, features, None, &orchestrator)
                .expect("task/artifact/read with task_id should succeed");
        assert_eq!(result["called"], json!("read_agent_artifact:task-spec-2"));

        // Legacy `agent_id` shape on the same aliases keeps working.
        let list_with_agent_id = RpcRequest::new(
            "req-list-agent",
            methods::TASK_ARTIFACT_LIST,
            json!({ "agent_id": "agent-legacy", "session_id": session_id.clone() }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&list_with_agent_id, features, None, &orchestrator)
                .expect("task/artifact/list with agent_id should still succeed");
        assert_eq!(result["called"], json!("list_agent_artifacts:agent-legacy"));

        let read_with_agent_id = RpcRequest::new(
            "req-read-agent",
            methods::TASK_ARTIFACT_READ,
            json!({
                "agent_id": "agent-legacy-2",
                "artifact_id": "artifact-2",
                "session_id": session_id.clone(),
            }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&read_with_agent_id, features, None, &orchestrator)
                .expect("task/artifact/read with agent_id should still succeed");
        assert_eq!(
            result["called"],
            json!("read_agent_artifact:agent-legacy-2")
        );

        // Both `agent_id` and `task_id` set: prefer `agent_id` so legacy
        // semantics win for compatibility.
        let list_with_both = RpcRequest::new(
            "req-list-both",
            methods::TASK_ARTIFACT_LIST,
            json!({
                "agent_id": "agent-wins",
                "task_id": "task-loses",
                "session_id": session_id.clone(),
            }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&list_with_both, features, None, &orchestrator)
                .expect("task/artifact/list with both ids should prefer agent_id");
        assert_eq!(result["called"], json!("list_agent_artifacts:agent-wins"));

        // Missing both -> invalid_params (not a crash, not silent default).
        let missing_both = RpcRequest::new(
            "req-missing",
            methods::TASK_ARTIFACT_LIST,
            json!({ "session_id": session_id }),
        );
        let err = raw_autonomy_rpc_with_orchestrator(&missing_both, features, None, &orchestrator)
            .expect_err("task/artifact/list without ids should fail");
        assert_eq!(err.code, rpc_error_codes::INVALID_PARAMS);
    }

    /// #1121 codex P1 re-review #3 acceptance: the `task_id` shape on
    /// `task/artifact/list` / `task/artifact/read` MUST require an
    /// explicit `session_id`. Otherwise a same-profile connection that
    /// knows another task's UUID would bypass the session/parent-child
    /// ownership check and reach its artifacts. The legacy `agent_id`
    /// shape still allows optional session_id for backwards compat.
    #[test]
    fn task_artifact_alias_task_id_requires_session_id() {
        let features = ConnectionUiFeatures::stdio_defaults();
        let orchestrator = RecordingOrchestrator::default();

        // task_id without session_id -> invalid_params.
        let list_no_session = RpcRequest::new(
            "req-list-task-no-session",
            methods::TASK_ARTIFACT_LIST,
            json!({ "task_id": "task-without-session" }),
        );
        let err =
            raw_autonomy_rpc_with_orchestrator(&list_no_session, features, None, &orchestrator)
                .expect_err("task_id without session_id must be rejected");
        assert_eq!(err.code, rpc_error_codes::INVALID_PARAMS);

        let read_no_session = RpcRequest::new(
            "req-read-task-no-session",
            methods::TASK_ARTIFACT_READ,
            json!({ "task_id": "task-without-session", "artifact_id": "art-1" }),
        );
        let err =
            raw_autonomy_rpc_with_orchestrator(&read_no_session, features, None, &orchestrator)
                .expect_err("task_id without session_id must be rejected on read");
        assert_eq!(err.code, rpc_error_codes::INVALID_PARAMS);

        // Sanity: legacy `agent_id` without session_id still works
        // (backwards-compat path, scoped by orchestrator-internal checks
        // that pre-date this alias).
        let session_id = SessionKey::new("api", "task-artifact-alias-bc");
        let agent_no_session = RpcRequest::new(
            "req-list-agent-no-session",
            methods::TASK_ARTIFACT_LIST,
            json!({ "agent_id": "legacy-agent" }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&agent_no_session, features, None, &orchestrator)
                .expect("legacy agent_id path keeps optional session_id semantics");
        assert_eq!(result["called"], json!("list_agent_artifacts:legacy-agent"));

        // And task_id WITH session_id still resolves normally.
        let list_with_session = RpcRequest::new(
            "req-list-task-with-session",
            methods::TASK_ARTIFACT_LIST,
            json!({ "task_id": "task-with-session", "session_id": session_id }),
        );
        let result =
            raw_autonomy_rpc_with_orchestrator(&list_with_session, features, None, &orchestrator)
                .expect("task_id + session_id should succeed");
        assert_eq!(
            result["called"],
            json!("list_agent_artifacts:task-with-session")
        );
    }

    #[test]
    fn aux_rest_to_ws_v1_route_rpc_rejects_methods_when_feature_not_negotiated() {
        // A client that sent ANY feature header but NOT
        // `auxiliary.rest_to_ws.v1` must see the aux methods rejected
        // with `method_not_supported`, matching the existing gate for
        // `task/list` behind `harness.task_control.v1`.
        let mut headers = HeaderMap::new();
        headers.insert(
            UI_FEATURES_HEADER,
            UI_PROTOCOL_FEATURE_HARNESS_TASK_CONTROL_V1
                .parse()
                .expect("header value"),
        );
        let features = ConnectionUiFeatures::from_headers_and_query(&headers, None);
        assert!(features.header_present);
        assert!(!features.auxiliary_rest_to_ws_v1);
        for method in [
            octos_core::ui_protocol::methods::SESSION_LIST,
            octos_core::ui_protocol::methods::SESSION_SNAPSHOT,
            octos_core::ui_protocol::methods::SESSION_DELETE,
            octos_core::ui_protocol::methods::SYSTEM_STATUS_GET,
            octos_core::ui_protocol::methods::CONTENT_LIST,
        ] {
            let request = RpcRequest::<Value>::new("req-1", method, Value::Null);
            let result = route_rpc_command(request, features);
            let err = result.expect_err("aux method must be rejected without feature");
            assert_eq!(
                err.code,
                octos_core::ui_protocol::rpc_error_codes::METHOD_NOT_SUPPORTED,
                "{method} must reject with METHOD_NOT_SUPPORTED"
            );
        }
    }

    #[test]
    fn aux_rest_to_ws_v1_route_rpc_accepts_methods_when_feature_negotiated() {
        let mut headers = HeaderMap::new();
        headers.insert(
            UI_FEATURES_HEADER,
            UI_PROTOCOL_FEATURE_AUXILIARY_REST_TO_WS_V1
                .parse()
                .expect("header value"),
        );
        let features = ConnectionUiFeatures::from_headers_and_query(&headers, None);
        assert!(features.auxiliary_rest_to_ws_v1);
        for (method, params) in [
            (
                octos_core::ui_protocol::methods::SESSION_LIST,
                Value::Object(serde_json::Map::new()),
            ),
            (
                octos_core::ui_protocol::methods::SYSTEM_STATUS_GET,
                Value::Object(serde_json::Map::new()),
            ),
        ] {
            let request = RpcRequest::<Value>::new("req-2", method, params);
            let cmd = route_rpc_command(request, features).expect("aux method accepted");
            assert_eq!(cmd.method(), method);
        }
    }

    /// Codex review 2026-05-12 (BLOCK 1): a client that sends NO
    /// feature header at all must still be rejected when it calls one
    /// of the M12 Phase D-1 auxiliary methods. The original
    /// implementation gated only when `features.header_present` was
    /// true, which let pre-existing no-header clients trip into
    /// `session/delete` / `content/delete` / etc. accidentally — that
    /// breaks the strict opt-in contract.
    #[test]
    fn aux_rest_to_ws_v1_route_rpc_rejects_methods_with_no_feature_header_at_all() {
        // No header, no query string — the legacy "advertise full
        // first-slice in SessionOpened" path. `header_present` must
        // be false (verified) and `auxiliary_rest_to_ws_v1` must be
        // false (verified), and yet the gate must fire.
        let headers = HeaderMap::new();
        let features = ConnectionUiFeatures::from_headers_and_query(&headers, None);
        assert!(
            !features.header_present,
            "no header → header_present must be false"
        );
        assert!(
            !features.auxiliary_rest_to_ws_v1,
            "no header → auxiliary.rest_to_ws.v1 must be false"
        );
        for method in [
            octos_core::ui_protocol::methods::SESSION_LIST,
            octos_core::ui_protocol::methods::SESSION_SNAPSHOT,
            octos_core::ui_protocol::methods::SESSION_MESSAGES_PAGE,
            octos_core::ui_protocol::methods::SESSION_STATUS_GET,
            octos_core::ui_protocol::methods::SESSION_FILES_LIST,
            octos_core::ui_protocol::methods::SESSION_TASKS_LIST,
            octos_core::ui_protocol::methods::SESSION_WORKSPACE_GET,
            octos_core::ui_protocol::methods::SESSION_TITLE_SET,
            octos_core::ui_protocol::methods::SESSION_DELETE,
            octos_core::ui_protocol::methods::SYSTEM_STATUS_GET,
            octos_core::ui_protocol::methods::CONTENT_LIST,
            octos_core::ui_protocol::methods::CONTENT_DELETE,
            octos_core::ui_protocol::methods::CONTENT_BULK_DELETE,
        ] {
            let request = RpcRequest::<Value>::new("req-no-header", method, Value::Null);
            let result = route_rpc_command(request, features);
            let err = result
                .expect_err("aux method must be rejected when no feature header was sent at all");
            assert_eq!(
                err.code,
                octos_core::ui_protocol::rpc_error_codes::METHOD_NOT_SUPPORTED,
                "{method} must reject with METHOD_NOT_SUPPORTED even with no header",
            );
        }
    }

    /// Codex review 2026-05-12 (BLOCK 1, companion): the legacy
    /// header-present gates (`session/hydrate`, `thread/graph/get`,
    /// `turn/state/get`, `task/list`, `task/cancel`,
    /// `task/restart_from_node`) must still pass through when no
    /// header was sent at all — that's the documented
    /// "advertise full first-slice in `SessionOpened`" fallback path.
    /// Only the new M12 Phase D-1 surface flips to strict opt-in.
    #[test]
    fn legacy_header_present_gates_still_accept_methods_with_no_feature_header() {
        // No header → all legacy gates fall through to
        // `UiCommand::from_rpc_request`. The decode itself may fail
        // because we send `Value::Null` as params, but the failure
        // must come from `from_rpc_request`, not from the gate.
        // Concretely: code must NOT be `METHOD_NOT_SUPPORTED`.
        let headers = HeaderMap::new();
        let features = ConnectionUiFeatures::from_headers_and_query(&headers, None);
        assert!(!features.header_present);
        for method in [
            octos_core::ui_protocol::methods::SESSION_HYDRATE,
            octos_core::ui_protocol::methods::THREAD_GRAPH_GET,
            octos_core::ui_protocol::methods::TURN_STATE_GET,
            octos_core::ui_protocol::methods::TASK_LIST,
            octos_core::ui_protocol::methods::TASK_CANCEL,
            octos_core::ui_protocol::methods::TASK_RESTART_FROM_NODE,
        ] {
            let request = RpcRequest::<Value>::new("req-legacy", method, Value::Null);
            let result = route_rpc_command(request, features);
            // Either Ok (unlikely for Null params) or Err with a
            // decode error — the key invariant is: NOT
            // `METHOD_NOT_SUPPORTED`.
            if let Err(err) = result {
                assert_ne!(
                    err.code,
                    octos_core::ui_protocol::rpc_error_codes::METHOD_NOT_SUPPORTED,
                    "{method} must NOT be rejected by capability gate when no header sent",
                );
            }
        }
    }

    /// Codex review 2026-05-12 (MEDIUM 1): a REST 404 from a
    /// session-scoped endpoint maps to `UNKNOWN_SESSION` with the
    /// addressed session id in `data.session_id`. The original
    /// implementation stuffed the method name into the session id
    /// slot ("session/messages_page: not found"), defeating
    /// reconciliation on the client side.
    #[tokio::test]
    async fn rest_status_to_rpc_error_404_session_context_echoes_session_id() {
        let context = RestResourceContext::session("sess-abc");
        let err = rest_status_to_rpc_error(
            octos_core::ui_protocol::methods::SESSION_MESSAGES_PAGE,
            axum::http::StatusCode::NOT_FOUND,
            Some("session not found".into()),
            &context,
        );
        assert_eq!(
            err.code,
            octos_core::ui_protocol::rpc_error_codes::UNKNOWN_SESSION,
        );
        let data = err.data.as_ref().expect("typed error data");
        assert_eq!(
            data.get("kind").and_then(Value::as_str),
            Some("unknown_session")
        );
        assert_eq!(
            data.get("session_id").and_then(Value::as_str),
            Some("sess-abc"),
            "session_id slot must carry the addressed session id, not the method name",
        );
        // The REST status + detail are still attached for debugging.
        assert_eq!(data.get("rest_status").and_then(Value::as_u64), Some(404));
        assert!(data.get("detail").is_some());
    }

    /// Codex review 2026-05-12 (MEDIUM 1, companion): a REST 404 from
    /// a non-session resource (content row, profile row) maps to the
    /// new `RESOURCE_NOT_FOUND` slot with `resource_type` +
    /// `identifier` echoed in `data`. Before this fix every 404 hit
    /// `UNKNOWN_SESSION` regardless of resource kind, which forced
    /// content/profile misses through a session-shaped error.
    #[tokio::test]
    async fn rest_status_to_rpc_error_404_resource_context_uses_not_found_slot() {
        let context = RestResourceContext::resource("content", "c-42");
        let err = rest_status_to_rpc_error(
            octos_core::ui_protocol::methods::CONTENT_DELETE,
            axum::http::StatusCode::NOT_FOUND,
            None,
            &context,
        );
        assert_eq!(
            err.code,
            octos_core::ui_protocol::rpc_error_codes::RESOURCE_NOT_FOUND,
            "non-session 404 must NOT collapse to UNKNOWN_SESSION",
        );
        let data = err.data.as_ref().expect("typed error data");
        assert_eq!(data.get("kind").and_then(Value::as_str), Some("not_found"));
        assert_eq!(
            data.get("resource_type").and_then(Value::as_str),
            Some("content"),
        );
        assert_eq!(data.get("identifier").and_then(Value::as_str), Some("c-42"),);
        assert_eq!(data.get("rest_status").and_then(Value::as_u64), Some(404));
    }

