        let loop_id = created["loop"]["loop_id"].as_str().expect("loop id");
        default_agent_orchestrator().force_loop_due_for_test(loop_id);

        let (ws, mut rx) = ws_connection_for_test(64);
        let ledger = Arc::new(UiProtocolLedger::new(64));
